// Formatar os dados do Google Sheets como base de conhecimento
const rows = $input.all();

let knowledgeBase = 'BASE DE CONHECIMENTO DA NOLA:\n\n';

for (const row of rows) {
  const d = row.json;
  if (d['Pergunta'] && d['Resposta']) {
    knowledgeBase += `[${d['Categoria'] || 'Geral'}]\n`;
    knowledgeBase += `Pergunta/Tema: ${d['Pergunta']}\n`;
    knowledgeBase += `Resposta: ${d['Resposta']}\n`;
    knowledgeBase += `---\n\n`;
  }
}

// Capturar a mensagem do usuário
const chatInput = $('When chat message received').item.json.chatInput || '';

return [{
  json: {
    knowledge_base: knowledgeBase,
    chat_input: chatInput
  }
}];
